const e=JSON.parse('{"key":"v-41aece29","path":"/pages/6bfb0fbf/","title":"Elasticsearch 文本分析","lang":"zh-CN","frontmatter":{"icon":"logos:elasticsearch","title":"Elasticsearch 文本分析","date":"2022-02-22T21:01:01.000Z","permalink":"/pages/6bfb0fbf/","category":["数据库","搜索引擎数据库","Elasticsearch"],"tag":["数据库","搜索引擎数据库","Elasticsearch","分词"],"description":"Elasticsearch 文本分析 文本分析是将非结构化文本转换为针对搜索优化的结构化格式的过程。 文本分析简介 文本分析使 Elasticsearch 能够执行全文搜索，其中搜索返回所有相关结果，而不仅仅是完全匹配。 文本分析可以分为两个方面： Tokenization（分词化） - 分析通过分词化使全文搜索成为可能：将文本分解成更小的块，称为分词。在大多数情况下，这些标记是单独的 term（词项）。 Normalizeation（标准化） - 经过分词后的文本只能进行词项匹配，但是无法进行同义词匹配。为解决这个问题，可以将文本进行标准化处理。例如：将 foxes 标准化为 fox。","head":[["meta",{"property":"og:url","content":"https://dunwu.github.io/waterdrop/waterdrop/pages/6bfb0fbf/"}],["meta",{"property":"og:site_name","content":"钝悟"}],["meta",{"property":"og:title","content":"Elasticsearch 文本分析"}],["meta",{"property":"og:description","content":"Elasticsearch 文本分析 文本分析是将非结构化文本转换为针对搜索优化的结构化格式的过程。 文本分析简介 文本分析使 Elasticsearch 能够执行全文搜索，其中搜索返回所有相关结果，而不仅仅是完全匹配。 文本分析可以分为两个方面： Tokenization（分词化） - 分析通过分词化使全文搜索成为可能：将文本分解成更小的块，称为分词。在大多数情况下，这些标记是单独的 term（词项）。 Normalizeation（标准化） - 经过分词后的文本只能进行词项匹配，但是无法进行同义词匹配。为解决这个问题，可以将文本进行标准化处理。例如：将 foxes 标准化为 fox。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-11-23T02:22:45.000Z"}],["meta",{"property":"article:author","content":"钝悟"}],["meta",{"property":"article:tag","content":"数据库"}],["meta",{"property":"article:tag","content":"搜索引擎数据库"}],["meta",{"property":"article:tag","content":"Elasticsearch"}],["meta",{"property":"article:tag","content":"分词"}],["meta",{"property":"article:published_time","content":"2022-02-22T21:01:01.000Z"}],["meta",{"property":"article:modified_time","content":"2024-11-23T02:22:45.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Elasticsearch 文本分析\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2022-02-22T21:01:01.000Z\\",\\"dateModified\\":\\"2024-11-23T02:22:45.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"钝悟\\",\\"url\\":\\"https://dunwu.github.io/waterdrop\\"}]}"]]},"headers":[{"level":2,"title":"文本分析简介","slug":"文本分析简介","link":"#文本分析简介","children":[]},{"level":2,"title":"Analyzer（分析器）","slug":"analyzer-分析器","link":"#analyzer-分析器","children":[{"level":3,"title":"测试分析器","slug":"测试分析器","link":"#测试分析器","children":[]},{"level":3,"title":"指定分析器","slug":"指定分析器","link":"#指定分析器","children":[]},{"level":3,"title":"自定义分析器","slug":"自定义分析器","link":"#自定义分析器","children":[]}]},{"level":2,"title":"中文分词","slug":"中文分词","link":"#中文分词","children":[]},{"level":2,"title":"Character Filters（字符过滤器）","slug":"character-filters-字符过滤器","link":"#character-filters-字符过滤器","children":[]},{"level":2,"title":"Tokenizer（分词器）","slug":"tokenizer-分词器","link":"#tokenizer-分词器","children":[]},{"level":2,"title":"Token Filters（分词过滤器）","slug":"token-filters-分词过滤器","link":"#token-filters-分词过滤器","children":[]},{"level":2,"title":"参考资料","slug":"参考资料","link":"#参考资料","children":[]}],"git":{"createdTime":1732232266000,"updatedTime":1732328565000,"contributors":[{"name":"dunwu","email":"forbreak@163.com","commits":2}]},"readingTime":{"minutes":8.95,"words":2685},"filePathRelative":"12.数据库/07.搜索引擎数据库/01.Elasticsearch/Elasticsearch_分析.md","localizedDate":"2022年2月22日","excerpt":"<h1> Elasticsearch 文本分析</h1>\\n<p><strong>文本分析</strong>是将非结构化文本转换为针对搜索优化的结构化格式的过程。</p>\\n<h2> 文本分析简介</h2>\\n<p>文本分析使 Elasticsearch 能够执行全文搜索，其中搜索返回所有相关结果，而不仅仅是完全匹配。</p>\\n<p>文本分析可以分为两个方面：</p>\\n<ul>\\n<li><strong>Tokenization（分词化）</strong> - 分析通过分词化使全文搜索成为可能：将文本分解成更小的块，称为分词。在大多数情况下，这些标记是单独的 term（词项）。</li>\\n<li><strong>Normalizeation（标准化）</strong> - 经过分词后的文本只能进行词项匹配，但是无法进行同义词匹配。为解决这个问题，可以将文本进行标准化处理。例如：将 <code>foxes</code> 标准化为 <code>fox</code>。</li>\\n</ul>","autoDesc":true}');export{e as data};
